<?php
 namespace League\CommonMark; class Converter implements ConverterInterface { protected $docParser; protected $htmlRenderer; public function __construct(DocParserInterface $docParser, ElementRendererInterface $htmlRenderer) { if (!($this instanceof MarkdownConverter)) { @trigger_error(sprintf('The %s class is deprecated since league/commonmark 1.4, use %s instead.', self::class, MarkdownConverter::class), E_USER_DEPRECATED); } $this->docParser = $docParser; $this->htmlRenderer = $htmlRenderer; } public function convertToHtml(string $commonMark): string { $documentAST = $this->docParser->parse($commonMark); return $this->htmlRenderer->renderBlock($documentAST); } public function __invoke(string $commonMark): string { return $this->convertToHtml($commonMark); } } 